import{c as a,Q as t,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"容器底层","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/25-容器底层.md","filePath":"osLearning/25-容器底层.md","lastUpdated":1781095972000}'),i={name:"osLearning/25-容器底层.md"};function o(p,s,r,l,d,c){return t(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="容器底层" tabindex="-1">容器底层 <a class="header-anchor" href="#容器底层" aria-label="Permalink to &quot;容器底层&quot;">​</a></h1><p>&quot;Docker 就是轻量级虚拟机&quot;——这句话大概是容器领域流传最广的错误认知,而且它真的会坑人:容器里 OOM 了,你去查宿主机内存,发现还空着 20G,百思不得其解;给 Pod 设了 <code>cpu: 500m</code>,服务 p99 周期性飞天,你查代码查 DB 查了一星期;<code>nproc</code> 显示 64 核,线程池开了 64 个线程,结果跑得比 4 线程还慢。这些问题的共同根源是:<strong>你以为容器是个&quot;小虚拟机&quot;,但它根本没有自己的内核——它就是宿主机上一个被&quot;戴了眼罩、套了缰绳&quot;的普通 Linux 进程</strong>。这一篇把眼罩和缰绳拆开看。</p><blockquote><p>一句话先记住:<strong>容器 = namespace(隔离&quot;你能看到什么&quot;)+ cgroup(限制&quot;你能用多少&quot;)+ OverlayFS(叠出&quot;你以为的文件系统&quot;)+ 一个普通 Linux 进程</strong>。<code>ps</code> 里看不到宿主机进程是 PID namespace,只能用半个核是 cgroup,文件系统像独立系统是 OverlayFS。<strong>容器问题最终全是 Linux 问题</strong>。</p></blockquote><hr><h2 id="一、容器-vs-虚拟机-差的是一整个内核" tabindex="-1">一、容器 vs 虚拟机:差的是一整个内核 <a class="header-anchor" href="#一、容器-vs-虚拟机-差的是一整个内核" aria-label="Permalink to &quot;一、容器 vs 虚拟机:差的是一整个内核&quot;">​</a></h2><p>把两套架构并排画出来,差别一目了然:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   虚拟机                          容器</span></span>
<span class="line"><span>─────────────────             ─────────────────</span></span>
<span class="line"><span>   App                            App</span></span>
<span class="line"><span>   Guest OS 内核   ← 每台一个       (没有这一层!)</span></span>
<span class="line"><span>   Hypervisor                    namespace + cgroup</span></span>
<span class="line"><span>   宿主机内核                      宿主机内核        ← 所有容器共享这一个</span></span>
<span class="line"><span>   硬件                           硬件</span></span></code></pre></div><p>虚拟机启动要走完一整个 OS 的启动流程(内核初始化、驱动加载、init 系统……),秒级到分钟级;<strong>容器启动只是 fork + exec 一个进程</strong>,毫秒级。虚拟机一台吃掉几百 MB 内存打底(Guest 内核自己就要占),容器的&quot;额外开销&quot;约等于零。</p><p>代价同样直白:<strong>所有容器共享宿主机内核</strong>。一个内核漏洞被容器内进程利用,整台宿主机连同所有邻居容器全部沦陷——这是第六节&quot;容器不是安全边界&quot;的根源。</p><table tabindex="0"><thead><tr><th>维度</th><th>虚拟机</th><th>容器</th></tr></thead><tbody><tr><td>隔离单位</td><td>完整虚拟硬件 + 独立内核</td><td>内核数据结构的&quot;视图&quot;</td></tr><tr><td>启动</td><td>秒~分钟</td><td><strong>毫秒</strong></td></tr><tr><td>密度</td><td>一台宿主机几十个</td><td>一台宿主机几百上千个</td></tr><tr><td>隔离强度</td><td>强(逃逸需穿透 Hypervisor)</td><td><strong>弱(共享内核)</strong></td></tr><tr><td>本质</td><td>模拟一台机器</td><td><strong>约束一个进程</strong></td></tr></tbody></table><hr><h2 id="二、namespace-隔离的是-视图-不是资源" tabindex="-1">二、namespace:隔离的是&quot;视图&quot;,不是资源 <a class="header-anchor" href="#二、namespace-隔离的是-视图-不是资源" aria-label="Permalink to &quot;二、namespace:隔离的是&quot;视图&quot;,不是资源&quot;">​</a></h2><p>namespace 干的事一句话能说完:<strong>让一组进程看到一个属于自己的、和别人不一样的系统视图</strong>。它不限制你用多少资源(那是 cgroup 的活),只决定&quot;你睁眼能看见什么&quot;。</p><p>Linux 目前有 8 种 namespace,每种遮住一类东西:</p><table tabindex="0"><thead><tr><th>namespace</th><th>隔离什么</th><th>容器里的体感</th></tr></thead><tbody><tr><td>PID</td><td>进程号视图</td><td>容器里 <code>ps</code> 只看到自己,主进程是 PID 1</td></tr><tr><td>NET</td><td>网卡 / 路由表 / 端口 / iptables</td><td>容器有自己的 eth0 和独立端口空间</td></tr><tr><td>MNT</td><td>挂载点</td><td>容器看到自己的 <code>/</code>,不是宿主机的</td></tr><tr><td>UTS</td><td>hostname / domain</td><td>每个容器有自己的主机名</td></tr><tr><td>IPC</td><td>System V IPC / POSIX 消息队列</td><td>共享内存不会跨容器串味</td></tr><tr><td>USER</td><td>用户 / 组 ID 映射</td><td>容器里的 root 可以映射成宿主机的普通用户</td></tr><tr><td>CGROUP</td><td>cgroup 视图</td><td>容器看不到宿主机的 cgroup 树全貌</td></tr><tr><td>TIME</td><td>系统时钟偏移</td><td>容器可以有不同的 uptime</td></tr></tbody></table><h3 id="_2-1-pid-namespace-一个进程-两个-pid" tabindex="-1">2.1 PID namespace:一个进程,两个 PID <a class="header-anchor" href="#_2-1-pid-namespace-一个进程-两个-pid" aria-label="Permalink to &quot;2.1 PID namespace:一个进程,两个 PID&quot;">​</a></h3><p>最能体现&quot;视图&quot;二字的例子。容器里跑 <code>ps aux</code>,你的服务是 PID 1;但在宿主机上 <code>ps</code> 一看,<strong>同一个进程是 PID 23847</strong>。它就是一个进程,只是在两个 namespace 里有两个号码——像一个人在公司有工号、在家叫小名。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>宿主机 PID namespace:    1(systemd) ... 23847(你的服务) ...</span></span>
<span class="line"><span>                                          ║ 同一个进程</span></span>
<span class="line"><span>容器 PID namespace:                       1(你的服务)</span></span></code></pre></div><p>副作用就是上一篇(24 篇)讲过的 <strong>PID 1 问题</strong>:容器主进程是它那个 namespace 里的 1 号,要承担 init 的职责——收养孤儿、回收僵尸,而且<strong>未注册 handler 的信号对 PID 1 不执行默认动作</strong>(SIGTERM 发了等于没发)。所以要么程序自己处理好信号和僵尸回收,要么用 tini / dumb-init 垫在前面。</p><h3 id="_2-2-net-namespace-每个容器一套独立网络栈" tabindex="-1">2.2 NET namespace:每个容器一套独立网络栈 <a class="header-anchor" href="#_2-2-net-namespace-每个容器一套独立网络栈" aria-label="Permalink to &quot;2.2 NET namespace:每个容器一套独立网络栈&quot;">​</a></h3><p>容器有自己的网卡、IP、路由表、iptables 规则、端口空间——所以两个容器可以同时监听&quot;自己的&quot;80 端口,互不冲突。容器和外界靠 veth pair(虚拟网线,一头插容器、一头插宿主机网桥)连通:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>容器 A: eth0 ──veth──┐</span></span>
<span class="line"><span>                      ├── docker0 网桥 ── 宿主机协议栈 ── 物理网卡</span></span>
<span class="line"><span>容器 B: eth0 ──veth──┘</span></span></code></pre></div><p>这就是 Docker 默认 bridge 模式。<code>-p 8080:80</code> 端口映射,底下不过是宿主机上一条 iptables DNAT 规则。</p><h3 id="_2-3-排查武器" tabindex="-1">2.3 排查武器 <a class="header-anchor" href="#_2-3-排查武器" aria-label="Permalink to &quot;2.3 排查武器&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsns</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                              # 列出系统上所有 namespace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ns/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 看某个进程属于哪些 namespace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nsenter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # &quot;钻进&quot;目标进程的网络 namespace 执行命令</span></span></code></pre></div><p><code>nsenter</code> 是排查容器网络的神器——<strong>容器里没装 ip/ss/tcpdump?不用进容器,从宿主机钻进它的 namespace 用宿主机的工具查</strong>。</p><hr><h2 id="三、cgroup-限制的是-用量" tabindex="-1">三、cgroup:限制的是&quot;用量&quot; <a class="header-anchor" href="#三、cgroup-限制的是-用量" aria-label="Permalink to &quot;三、cgroup:限制的是&quot;用量&quot;&quot;">​</a></h2><p>namespace 管&quot;看见&quot;,cgroup(control group)管&quot;用量&quot;:CPU、内存、进程数(pids)、块设备 IO(io)、绑核(cpuset)……它是一棵树,资源限制沿树往下分:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sys/fs/cgroup/                     ← cgroup v2 统一树根</span></span>
<span class="line"><span>├── system.slice/                   ← systemd 服务们</span></span>
<span class="line"><span>└── kubepods.slice/</span></span>
<span class="line"><span>    ├── pod-aaa/</span></span>
<span class="line"><span>    │   ├── container-1/   cpu.max = &quot;50000 100000&quot;   ← 你的 CPU limit 落在这</span></span>
<span class="line"><span>    │   └── container-2/   memory.max = &quot;536870912&quot;   ← 你的 memory limit 落在这</span></span>
<span class="line"><span>    └── pod-bbb/ ...</span></span></code></pre></div><p><strong>K8s 的 <code>resources.limits</code> 不是什么编排黑魔法,就是往这些文件里写数字</strong>。下面两个小节,是容器性能问题的两大名场面。</p><h3 id="_3-1-cpu-limit-cfs-quota-p99-飞天事件" tabindex="-1">3.1 CPU limit = CFS quota:p99 飞天事件 <a class="header-anchor" href="#_3-1-cpu-limit-cfs-quota-p99-飞天事件" aria-label="Permalink to &quot;3.1 CPU limit = CFS quota:p99 飞天事件&quot;">​</a></h3><p>K8s 里 <code>limits.cpu: 500m</code> 会被翻译成 CFS 带宽控制(16 篇调度器讲过 CFS):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cpu.max = 50000 100000</span></span>
<span class="line"><span>          ↑quota  ↑period</span></span>
<span class="line"><span>意思:每 100ms 的周期内,这组进程总共只能跑 50ms CPU</span></span></code></pre></div><p>注意是&quot;总共&quot;——名场面来了:你的服务有 8 个工作线程,流量尖峰时 8 个线程同时开跑,<strong>50ms 的配额 6ms 就烧完了</strong>(8 线程 × 6ms ≈ 50ms),接下来这个周期剩下的 94ms 里,整个容器被内核摁住一动不能动(throttle),所有请求干等:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>period(100ms):  |■■■■■■ 烧完quota(6ms) | ░░░░░░░░ 全员冻结 94ms ░░░░░░░░ |</span></span>
<span class="line"><span>                                          ↑ 此刻到达的请求,延迟 +94ms 起步</span></span>
<span class="line"><span>p50 看起来很正常,p99 周期性地多出几十上百毫秒 → &quot;p99 飞天,但 CPU 利用率才 50%&quot;</span></span></code></pre></div><p><strong>CPU 平均利用率完全正常、监控曲线岁月静好,但 p99 周期性抖动</strong>——这是容器时代最经典的性能谜案。确诊只需要一条命令:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/cpu.stat</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># nr_throttled    被限流的周期数 ← 这个在涨,就是它</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># throttled_usec  总共被冻结了多久</span></span></code></pre></div><p>解法:调大 limit、把线程数压到和 quota 匹配、或对延迟敏感的服务干脆不设 CPU limit(只设 request)。</p><h3 id="_3-2-memory-limit-cgroup-oom-容器死了-宿主机没事" tabindex="-1">3.2 memory limit = cgroup OOM:容器死了,宿主机没事 <a class="header-anchor" href="#_3-2-memory-limit-cgroup-oom-容器死了-宿主机没事" aria-label="Permalink to &quot;3.2 memory limit = cgroup OOM:容器死了,宿主机没事&quot;">​</a></h3><p>另一个名场面:<strong>容器被 OOM kill 了,你登上宿主机一看,<code>free -h</code> 显示还有 20G 空闲</strong>。</p><p>这不矛盾。容器的 memory limit 是 cgroup 的私有红线:<strong>容器内进程的内存总和摸到 <code>memory.max</code>,cgroup 的 OOM killer 就在这个容器内部杀进程</strong>——跟宿主机整体内存余量没有任何关系。宿主机的 OOM killer 是另一套独立机制,只在整机内存耗尽时出手。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.current</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 当前用量(包含 page cache!)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.events</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # oom_kill 计数在涨 = 发生过 cgroup OOM</span></span></code></pre></div><p>两个工程要点:</p><ul><li><strong>memory.current 包含这个 cgroup 产生的 page cache</strong>——读写大文件会把它顶上去,但 cache 是可回收的,逼近 limit 时内核会先回收 cache 再 OOM。看到用量贴着 limit 别先慌,查 <code>memory.stat</code> 分清 RSS 和 cache。</li><li><strong>runtime 必须感知容器限制</strong>。JVM 老版本按宿主机内存算默认堆大小,在 64G 宿主机上的 512M 容器里直接起飞就 OOM(新版 JVM 默认 <code>UseContainerSupport</code>);Go 用 <code>GOMEMLIMIT</code>,线程池按 cgroup quota 而不是 <code>nproc</code> 配——详见第七节&quot;三大错觉&quot;。</li></ul><hr><h2 id="四、overlayfs-镜像是怎么叠出来的" tabindex="-1">四、OverlayFS:镜像是怎么叠出来的 <a class="header-anchor" href="#四、overlayfs-镜像是怎么叠出来的" aria-label="Permalink to &quot;四、OverlayFS:镜像是怎么叠出来的&quot;">​</a></h2><p>容器的文件系统看起来是个完整的 Linux 根目录,其实是 OverlayFS 把多层目录&quot;叠&quot;出来的幻象:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>merged(容器看到的 /)        ← 你以为的文件系统</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span>upperdir(容器可写层)        ← 你写的所有东西都落在这,容器删了就没</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span>lowerdir: 镜像 layer 3       ← COPY app /app</span></span>
<span class="line"><span>          镜像 layer 2       ← RUN apt install ...</span></span>
<span class="line"><span>          镜像 layer 1       ← FROM ubuntu 基础层</span></span>
<span class="line"><span>                              (全部只读,多个容器共享同一份!)</span></span></code></pre></div><p>Dockerfile 里每条产生文件变更的指令就是一层。<strong>只读层全机共享</strong>——100 个容器用同一个 ubuntu 基础镜像,磁盘上那 80MB 只存一份,这是容器密度高的另一半秘密。</p><p>读写规则是经典的写时复制(copy-on-write,06 篇 fork 的 COW 是同一个思想):</p><ul><li><strong>读</strong>:从上往下找,谁先有就读谁的</li><li><strong>写</strong>:文件在只读层?先把<strong>整个文件</strong>拷到 upperdir 再改(copy-up)</li><li><strong>删</strong>:只读层的文件删不掉,在 upperdir 放一个 whiteout 标记把它&quot;遮住&quot;</li></ul><p>三个工程后果:</p><ol><li><strong>第一次写大文件可能卡一下</strong>——改 1GB 文件的 1 个字节,要先 copy-up 整个 1GB。</li><li><strong>镜像瘦不下来</strong>:<code>RUN rm -rf /big-file</code> 只是加了层 whiteout,下面那层的文件还在镜像里占体积。要在<strong>同一条 RUN</strong> 里下载并删除。</li><li><strong>可写层不是放数据的地方</strong>——容器删除即蒸发,且 OverlayFS 的写路径性能不如原生文件系统。<strong>数据库、日志、一切要活过容器生命周期的数据,用 volume / bind mount 直通宿主机文件系统</strong>(文件系统写入路径详见 19 篇)。</li></ol><hr><h2 id="五、runc-与-oci-容器是怎么被-拉起来-的" tabindex="-1">五、runc 与 OCI:容器是怎么被&quot;拉起来&quot;的 <a class="header-anchor" href="#五、runc-与-oci-容器是怎么被-拉起来-的" aria-label="Permalink to &quot;五、runc 与 OCI:容器是怎么被&quot;拉起来&quot;的&quot;">​</a></h2><p>把 namespace、cgroup、OverlayFS 三块拼图组装成一个跑起来的容器,这活由 runc 干。整条链路:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker run nginx</span></span>
<span class="line"><span>  → dockerd(API、镜像管理)</span></span>
<span class="line"><span>  → containerd(容器生命周期管理)</span></span>
<span class="line"><span>  → runc(真正干活的,一个小 CLI)</span></span>
<span class="line"><span>       → clone(CLONE_NEWPID | CLONE_NEWNET | ...)   创建各 namespace</span></span>
<span class="line"><span>       → 写 /sys/fs/cgroup/...                       套上 cgroup 限制</span></span>
<span class="line"><span>       → pivot_root 切到 OverlayFS 的 merged 目录     换上容器的 rootfs</span></span>
<span class="line"><span>       → 装 seccomp 过滤器、丢 capabilities           收走危险权限</span></span>
<span class="line"><span>       → execve(&quot;/usr/sbin/nginx&quot;)                   变身成你的进程</span></span></code></pre></div><p>看清楚最后一步——<strong>runc 自己 exec 成了你的容器进程</strong>。没有常驻的&quot;容器引擎&quot;夹在中间,容器跑起来之后就是一个普通进程,Docker 退场。</p><p>OCI(Open Container Initiative)规范定义了两件事:<strong>runtime spec</strong>(一个 JSON 描述怎么运行容器)和 <strong>image spec</strong>(镜像的层和元数据怎么打包)。所以 Docker、containerd、Podman、K8s 的 CRI 实现可以互换底层 runtime——<strong>容器底层不是黑盒,就是一串 Linux syscall 的标准化组合</strong>(进程创建那一段,11 篇 fork/exec 全讲过)。</p><hr><h2 id="六、容器不是安全边界" tabindex="-1">六、容器不是安全边界 <a class="header-anchor" href="#六、容器不是安全边界" aria-label="Permalink to &quot;六、容器不是安全边界&quot;">​</a></h2><p>再强调一次:<strong>所有容器共享宿主机内核</strong>。VM 逃逸要穿透 Hypervisor,难如登天;容器&quot;逃逸&quot;很多时候只需要一个内核漏洞,或者——更常见的——<strong>一个作死的配置</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--privileged</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                # 全部 capabilities + 全部设备,等于宿主机 root</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /:/host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                  # 宿主机根目录直接挂进来,还隔离什么</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/docker.sock:/var/run/docker.sock</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 能跟 dockerd 说话 = 能起 privileged 容器 = root</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--pid</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">host</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --net=host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 直接放弃 PID / 网络隔离</span></span></code></pre></div><p>这几条里任何一条,都等于把宿主机钥匙交给了容器。加固清单(每条对应一类攻击面):</p><ul><li><strong>容器内用非 root 用户跑</strong>(Dockerfile 写 <code>USER</code>)——逃逸出去也只是普通用户</li><li><strong>user namespace 重映射</strong>——容器里的 root 在宿主机上是个 nobody</li><li><strong>capabilities 最小化</strong>——默认就别给 <code>SYS_ADMIN</code> 这种万能钥匙</li><li><strong>seccomp</strong>——按白名单过滤 syscall,砍掉攻击面(Docker 默认 profile 禁了 40+ 个)</li><li><strong>AppArmor / SELinux</strong>——强制访问控制兜底</li><li><strong>read-only rootfs</strong>——写不进去,植入后门都难</li></ul><p>真需要强隔离(多租户跑不可信代码),答案是 gVisor / Kata / Firecracker microVM——<strong>给容器找回一个属于自己的内核</strong>,28 篇会再提到。</p><hr><h2 id="七、容器里的三大错觉" tabindex="-1">七、容器里的三大错觉 <a class="header-anchor" href="#七、容器里的三大错觉" aria-label="Permalink to &quot;七、容器里的三大错觉&quot;">​</a></h2><p>容器内的程序经常&quot;看错&quot;自己的处境,三个最常见的:</p><p><strong>错觉一:<code>nproc</code> 说我有 64 核。</strong> namespace 不隔离 CPU 视图,容器内看到的是宿主机全部核数;但 cgroup quota 可能只给你 1 核。无脑按 <code>nproc</code> 开线程池,64 个线程抢 1 核的 quota——回看 3.1 节,throttle 抖动直接拉满。<strong>线程数要按 cgroup quota 配</strong>(现代 JVM / Go 已自动识别,老版本和自己写的代码要手动)。</p><p><strong>错觉二:<code>free</code> 说我有 64G 内存。</strong> 同理,<code>/proc/meminfo</code> 没有被 namespace 化,<code>free</code> 看到的是宿主机内存。容器真正的红线在 <code>/sys/fs/cgroup/memory.max</code>。<strong>以 cgroup 文件为准,永远</strong>。</p><p><strong>错觉三:我的进程不用管 init 的事。</strong> 你是 PID 1,你就是 init:不收养孤儿、不回收僵尸、不转发信号,这些锅都是你的(24 篇讲透了)。一行 <code>ENTRYPOINT [&quot;tini&quot;, &quot;--&quot;, &quot;your-app&quot;]</code> 能省很多事。</p><hr><h2 id="八、排查工具箱-什么症状查哪里" tabindex="-1">八、排查工具箱:什么症状查哪里 <a class="header-anchor" href="#八、排查工具箱-什么症状查哪里" aria-label="Permalink to &quot;八、排查工具箱:什么症状查哪里&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>查什么</th></tr></thead><tbody><tr><td>p99 周期性抖动</td><td><code>cat /sys/fs/cgroup/cpu.stat</code> 看 <code>nr_throttled</code></td></tr><tr><td>容器莫名重启 / 进程被杀</td><td><code>cat /sys/fs/cgroup/memory.events</code> 看 <code>oom_kill</code>;<code>dmesg -T | grep -i oom</code></td></tr><tr><td>内存用量比预期高</td><td><code>memory.current</code> vs <code>memory.stat</code> 里的 RSS / cache 拆解</td></tr><tr><td>容器网络不通</td><td><code>nsenter -t &lt;pid&gt; -n ip addr / ip route / ss -lntp</code></td></tr><tr><td>想知道某进程在哪个容器</td><td><code>cat /proc/&lt;pid&gt;/cgroup</code>(路径里有容器 ID)</td></tr><tr><td>进程数涨到上限 fork 失败</td><td><code>cat /sys/fs/cgroup/pids.current</code> vs <code>pids.max</code></td></tr><tr><td>容器文件系统行为怪</td><td><code>mount | grep overlay</code> 看 lower/upper 的真实目录</td></tr><tr><td>看容器的全部隔离配置</td><td><code>docker inspect &lt;id&gt;</code>、<code>lsns</code></td></tr></tbody></table><p>记住这张表的用法:<strong>别停在 Docker / K8s 的名词层面排障</strong>。&quot;Pod 被驱逐&quot;&quot;容器 CrashLoopBackOff&quot;都是表象,往下挖一层,答案几乎总在 namespace、cgroup、OverlayFS 这三件套里。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>把容器当轻量级虚拟机</strong>——它没有自己的内核,隔离强度、安全边界、资源视图全都和 VM 不是一回事,这个心智错误是后面所有坑的总根源。</li><li><strong>按 <code>nproc</code> / <code>free</code> 配置线程池和堆大小</strong>——容器里这俩看到的是宿主机,真实限制在 <code>/sys/fs/cgroup</code> 下,老版本 JVM 因此直接起飞 OOM。</li><li><strong>设了 CPU limit 却想不通 p99 抖动</strong>——CFS quota 烧完就冻结到周期结束,<code>nr_throttled</code> 一查便知,CPU 平均利用率不高不代表没被限流。</li><li><strong>容器 OOM 跑去查宿主机内存</strong>——cgroup OOM 是容器自己的红线,和宿主机剩多少内存无关。</li><li><strong>重要数据写进容器可写层</strong>——容器一删数据蒸发,OverlayFS 写性能也差,持久数据必须走 volume。</li><li><strong>Dockerfile 里先 COPY 大文件再 rm</strong>——删除只是 whiteout 遮住,镜像体积一点没小,下载和删除要在同一层。</li><li><strong><code>--privileged</code> / 挂载 docker.sock 图省事</strong>——等于把宿主机 root 拱手送人,生产环境一票否决。</li><li><strong>裸跑应用当 PID 1</strong>——信号收不到(每次停机等 30s 强杀)、僵尸没人收,tini 两行配置的事。</li><li><strong>排障停在 K8s 名词层</strong>——&quot;Pod 异常&quot;不是根因,<code>kubectl describe</code> 之后要敢往 cgroup 文件和 <code>dmesg</code> 里钻。</li></ol><hr><p>下一篇:<code>26-性能工具.md</code>,把前面 25 篇的知识变成动手能力——<strong>60 秒全局体检怎么做</strong>、top / vmstat / iostat / ss 各自回答什么问题、<strong>perf 采样原理和火焰图怎么三分钟定位 CPU 热点</strong>、strace 为什么不能乱挂,以及一套&quot;什么症状用什么工具&quot;的排查剧本。</p>`,82)])])}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
